script:
// ===============================
// Helper: normalize & toggle value fields
// ===============================

function apply_readonly_logic(frm, cdt, cdn, kniterp_field_type) {
    const cur_row  = locals[cdt][cdn];
    const grid_row = frm.fields_dict.custom_textile_attributes.grid.grid_rows_by_docname[cdn];
    if (grid_row) {
        if (kniterp_field_type === "Int" || kniterp_field_type === "Float") {
            grid_row.toggle_editable('kniterp_value', false);
            grid_row.toggle_editable('kniterp_numeric_value', true);
        }
        else if (kniterp_field_type === "Select") {
            grid_row.toggle_editable('kniterp_value', true);
            grid_row.toggle_editable('kniterp_numeric_value', false);
        }
    }
}


function kniterp_normalize_attribute_row(frm, row) {
    // 1️⃣ Compute display value
    if (row.kniterp_value) {
        row.kniterp_display_value = row.kniterp_value;
    } else if (
        row.kniterp_numeric_value !== null &&
        row.kniterp_numeric_value !== undefined
    ) {
        row.kniterp_display_value = String(row.kniterp_numeric_value);
    } else {
        row.kniterp_display_value = "";
    }
}


// ===============================
// Naming & Code Preview
// ===============================
function update_naming_preview(frm) {

    if (!["Fabric", "Yarn"].includes(frm.doc.custom_item_classification)) {
        frm.set_value("item_name", "");
        frm.set_value("item_code", "");
        return;
    }
    
    const rows = (frm.doc.custom_textile_attributes || [])
        .filter(r => r.kniterp_display_value)
        .sort((a, b) => (a.kniterp_sequence || 0) - (b.kniterp_sequence || 0));

    // -------- Item Name --------
    const name_parts = rows
        .filter(r => r.kniterp_affects_naming)
        .map(r => r.kniterp_display_value);

    frm.set_value("item_name", name_parts.join(" "));

    // -------- Item Code --------
    const code_parts = [];
    rows.forEach(r => {
        if (!r.kniterp_affects_code) return;
        if (r.kniterp_short_code) {
            code_parts.push(r.kniterp_short_code);
        } else if (r.kniterp_numeric_value !== null && r.kniterp_numeric_value !== undefined) {
            code_parts.push(String(r.kniterp_numeric_value));
        }
    });

    const prefix = frm.doc.custom_item_classification === "Fabric" ? "FB" : "YR";
    frm.set_value(
        "item_code",
        code_parts.length ? `${prefix}-${code_parts.join("-")}` : ""
    );
}


// ===============================
// Apply rules (single source of truth)
// ===============================
function kniterp_apply_attribute_rules(frm) {

    (frm.doc.custom_textile_attributes || []).forEach(row => {
        kniterp_normalize_attribute_row(frm, row);
    });

    frm.refresh_field("custom_textile_attributes");  // Refresh to apply df changes
    
    update_naming_preview(frm);
}


// ===============================
// Duplicate attribute check
// ===============================
function is_duplicate_attribute(frm) {

    const seen = new Set();

    for (const row of frm.doc.custom_textile_attributes || []) {
        if (!row.kniterp_attribute) continue;

        if (seen.has(row.kniterp_attribute)) return true;
        seen.add(row.kniterp_attribute);
    }

    return false;
}


// ===============================
// Child: Item Textile Attribute
// ===============================
frappe.ui.form.on("Item Textile Attribute", {

    kniterp_attribute(frm, cdt, cdn) {

        const row = locals[cdt][cdn];
        if (!row.kniterp_attribute) return;

        if (is_duplicate_attribute(frm)) {
            frappe.msgprint({
                title: "Duplicate Attribute",
                message: "This attribute is already added.",
                indicator: "red"
            });
            row.kniterp_attribute = null;
            // frm.refresh_field("custom_textile_attributes");
            return;
        }

        frappe.db.get_doc("Textile Attribute", row.kniterp_attribute)
            .then(attr => {
                
                row.kniterp_sequence = attr.kniterp_sequence;
                row.kniterp_affects_naming = attr.kniterp_affects_naming;
                row.kniterp_affects_code = attr.kniterp_affects_code;
                row.kniterp_searchable = attr.kniterp_searchable;
                row.kniterp_is_active = attr.kniterp_is_active;
                row.kniterp_field_type = attr.kniterp_field_type;
                
                // apply_readonly_logic(frm, cdt, cdn, row.kniterp_field_type);
                
                // reset values
                if (attr.kniterp_field_type === "Select") {
                    row.kniterp_numeric_value = null;
                }
                
                if (["Int", "Float"].includes(attr.kniterp_field_type)) {
                    row.kniterp_value = null;
                }

                frm.refresh_field("custom_textile_attributes");
                
            });
    },

    kniterp_value(frm, cdt, cdn) {
        kniterp_apply_attribute_rules(frm);
        
        const row = locals[cdt][cdn];
        if (!row.kniterp_value) return;

        // Fetch Textile Attribute Value to get short_code
        frappe.db.get_value(
            "Textile Attribute Value",
            row.kniterp_value,
            "kniterp_short_code"
        ).then(r => {
            row.kniterp_short_code = r.message.kniterp_short_code || "";
            row.kniterp_display_value = row.kniterp_value;

            frm.refresh_field("custom_textile_attributes");
            update_naming_preview(frm);
        });
    },

    kniterp_numeric_value(frm) {
        kniterp_apply_attribute_rules(frm);
    },

    custom_textile_attributes_add(frm) {
        kniterp_apply_attribute_rules(frm);
    },

    custom_textile_attributes_remove(frm) {
        kniterp_apply_attribute_rules(frm);
    }
});


// ===============================
// Parent: Item
// ===============================
frappe.ui.form.on("Item", {
    
    onload_post_render(frm) {
        // 2️⃣ Prefill (once)
        if (!frm._kniterp_prefilled) {
            const raw = sessionStorage.getItem("kniterp_new_item_payload");
            if (!raw) return;
    
            frm._kniterp_prefilled = true;
            const payload = JSON.parse(raw);
    
            if (payload.classification) {
                frm.set_value("custom_item_classification", payload.classification);
                // set_item_readonly_lock(frm);  // Re-apply lock after setting classification
            }
    
            if (payload.textile_attributes?.length) {
                frm.clear_table("custom_textile_attributes");
    
                // Fetch all Textile Attribute docs to set row properties
                const promises = payload.textile_attributes.map(a => {
                    return Promise.all([
                        frappe.db.get_doc("Textile Attribute", a.kniterp_attribute),
                        a.kniterp_value
                            ? frappe.db.get_value(
                                "Textile Attribute Value",
                                a.kniterp_value,
                                "kniterp_short_code"
                              )
                            : Promise.resolve(null)
                    ]);
                });
                
                Promise.all(promises)
                    .then(results => {
                        results.forEach(([attrDoc, valueRes], i) => {
                            const a = payload.textile_attributes[i];
                
                            const row = frm.add_child("custom_textile_attributes");
                
                            // Base values
                            row.kniterp_attribute = a.kniterp_attribute || null;
                            row.kniterp_value = a.kniterp_value || null;
                            row.kniterp_numeric_value = a.kniterp_numeric_value ?? null;
                
                            // Attribute master fields
                            row.kniterp_sequence = attrDoc.kniterp_sequence;
                            row.kniterp_affects_naming = attrDoc.kniterp_affects_naming;
                            row.kniterp_affects_code = attrDoc.kniterp_affects_code;
                            row.kniterp_searchable = attrDoc.kniterp_searchable;
                            row.kniterp_is_active = attrDoc.kniterp_is_active;
                            row.kniterp_field_type = attrDoc.kniterp_field_type;
                
                            // Value short code
                            row.kniterp_short_code =
                                valueRes?.message?.kniterp_short_code || "";
                        });
                
                        frm.refresh_field("custom_textile_attributes");
                        kniterp_apply_attribute_rules(frm);
                    })
                    .catch(err => {
                        frappe.msgprint("Error loading attributes from session storage.");
                    });
            }
            sessionStorage.removeItem("kniterp_new_item_payload");
        }
    },

    refresh(frm) {
        // 1️⃣ Lock item_name & item_code
        // set_item_readonly_lock(frm);
        // kniterp_apply_attribute_rules(frm);
    },

    // 3️⃣ Classification change
    custom_item_classification(frm) {
        frm.set_value("item_code", "");
        update_naming_preview(frm);
    },

    // 4️⃣ Before save safeguard
    before_save(frm) {

        if (
            !frm.doc.item_code &&
            ["Fabric", "Yarn"].includes(frm.doc.custom_item_classification)
        ) {
            frm.set_value(
                "item_code",
                "TEMP-" + frappe.utils.get_random(6)
            );
        }
    }
});
